import sys

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    out = []
    for i in range(1, T + 1):
        nums = list(map(int, data[i].split()))
        out.append(str(sum(nums)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

